{
  "query": "mutation Login($input: LoginInput!) { auth { login(input: $input) { accessToken refreshToken user { uuid email name } } } }",
  "variables": {
    "input": {
      "email": "{{email}}",
      "password": "{{password}}"
    }
  }
}

{
  "query": "query ListS3Files($prefix: String) { s3 { s3Files(prefix: $prefix) { files { key filename size lastModified contentType } total bucketDisplayName } } }",
  "variables": { "prefix": "{{prefix}}" }
}

{
  "query": "query GetS3FileInfo($fileKey: String!) { s3 { s3FileInfo(fileKey: $fileKey) { key filename size lastModified contentType } } }",
  "variables": { "fileKey": "{{fileKey}}" }
}

{
  "query": "query GetS3FileData($fileKey: String!, $limit: Int!, $offset: Int) { s3 { s3FileData(fileKey: $fileKey, limit: $limit, offset: $offset) { fileKey rows { data } limit offset totalRows } } }",
  "variables": { "fileKey": "{{fileKey}}", "limit": 100, "offset": 0 }
}

{
  "query": "query GetS3FileDownloadUrl($fileKey: String!, $expiresIn: Int) { s3 { s3FileDownloadUrl(fileKey: $fileKey, expiresIn: $expiresIn) { downloadUrl expiresIn } } }",
  "variables": { "fileKey": "{{fileKey}}", "expiresIn": 3600 }
}

{
  "query": "query GetS3FileSchema($fileKey: String!) { s3 { s3FileSchema(fileKey: $fileKey) { name type nullable } } }",
  "variables": { "fileKey": "{{fileKey}}" }
}

{
  "query": "mutation InitiateCsvUpload($input: InitiateCsvUploadInput!) { s3 { initiateCsvUpload(input: $input) { uploadId fileKey chunkSize numParts } } }",
  "variables": { "input": { "filename": "sample.csv", "file_size": 1024 } }
}

{
  "query": "mutation CompleteCsvUpload($input: CompleteUploadInput!) { s3 { completeCsvUpload(input: $input) { status fileKey s3Url location } } }",
  "variables": { "input": { "upload_id": "{{upload_id}}" } }
}

{
  "query": "query GetUploadStatus($upload_id: String!) { upload { uploadStatus(upload_id: $upload_id) { upload_id file_key file_size chunk_size uploaded_parts total_parts uploaded_bytes status } } }",
  "variables": { "upload_id": "{{upload_id}}" }
}

{
  "query": "query GetPresignedUrl($uploadId: String!, $partNumber: Int!) { upload { presignedUrl(uploadId: $uploadId, partNumber: $partNumber) { presignedUrl partNumber alreadyUploaded etag } } }",
  "variables": { "uploadId": "{{upload_id}}", "partNumber": {{part_number}} }
}

{
  "query": "mutation RegisterPart($input: RegisterPartInput!) { upload { registerPart(input: $input) { status partNumber } } }",
  "variables": { "input": { "uploadId": "{{upload_id}}", "partNumber": {{part_number}}, "etag": "{{etag}}" } }
}

{
  "query": "mutation AbortUpload($input: AbortUploadInput!) { upload { abortUpload(input: $input) { status upload_id } } }",
  "variables": { "input": { "upload_id": "{{upload_id}}" } }
}
